executeFunc((function init_centrifugo_notification_qKWmx1KEt(){if(typeof centrifuge!=="object"){return false}if(window.current_profile){const personal_notification_channel=centrifuge.newSubscription(window.current_profile+"_notification");personal_notification_channel.on("publication",(function(ctx){if(ctx.data.profile===window.current_profile){let notification=`{\n                      "type": "${ctx.data.type}",\n                      "header": "${ctx.data.header}",\n                      "message": "${ctx.data.message}"\n                    }`;createToast(JSON.parse(notification))}})).subscribe()}if(window.profile_id){const profile_notification_channel=centrifuge.newSubscription(window.profile_id+"_notification");profile_notification_channel.on("publication",(function(ctx){if(ctx.data.profile===window.profile_id){let notification=`{\n                      "type": "${ctx.data.type}",\n                      "header": "${ctx.data.header}",\n                      "message": "${ctx.data.message}"\n                    }`;createToast(JSON.parse(notification))}})).subscribe()}return true}),100);